const body = $input.first().json.body || $input.first().json;
const entry = (body.entry || [])[0];
if (!entry) return [];
const change = (entry.changes || [])[0];
if (!change || change.field !== 'messages') return [];
const value = change.value || {};
const msg = (value.messages || [])[0];
if (!msg) return [];

const contact = (value.contacts || [])[0];
const phoneNumberId = value.metadata?.phone_number_id || '';

let normalized = (msg.from || '').replace(/[\s\-\(\)\+]/g, '');
if (normalized.startsWith('0034')) normalized = normalized.slice(4);
if (normalized.length === 9) normalized = '34' + normalized;

const result = {
  from: msg.from,
  from_name: contact?.profile?.name || msg.from,
  normalized_phone: normalized,
  message_id: msg.id,
  timestamp: msg.timestamp,
  msg_type: msg.type,
  phone_number_id: phoneNumberId,
  media_id: null,
  mime_type: null,
  caption: null,
  filename: null,
  text_body: null,
  button_reply_id: null,
  button_reply_title: null,
  list_reply_id: null,    // PR_BOT_2
  list_reply_title: null,
};

switch (msg.type) {
  case 'image':
    result.media_id = msg.image.id;
    result.mime_type = msg.image.mime_type;
    result.caption = msg.image.caption || null;
    result.filename = `whatsapp-${msg.from}-${Date.now()}.jpg`;
    break;
  case 'document':
    result.media_id = msg.document.id;
    result.mime_type = msg.document.mime_type;
    result.caption = msg.document.caption || null;
    result.filename = msg.document.filename || `whatsapp-${msg.from}-${Date.now()}.pdf`;
    break;
  case 'audio':
    result.media_id = msg.audio.id;
    result.mime_type = msg.audio.mime_type;
    result.filename = `voice-${msg.from}-${Date.now()}.ogg`;
    break;
  case 'text':
    result.text_body = msg.text?.body || null;
    break;
  case 'interactive':
    if (msg.interactive?.type === 'button_reply') {
      result.button_reply_id = msg.interactive.button_reply.id;
      result.button_reply_title = msg.interactive.button_reply.title;
    } else if (msg.interactive?.type === 'list_reply') {
      // // PR_BOT_2: list_reply (selección org)
      result.list_reply_id = msg.interactive.list_reply.id;
      result.list_reply_title = msg.interactive.list_reply.title;
      // // PR_BOT_2_1: no sobrescribir text_body con list_reply_title
      // (contaminación cross-feature; los downstream que necesiten texto
      // ya tienen list_reply_title explícito).
    }
    break;
}


return [{ json: result }];

// Config
const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

const parsed = $('Parsear Mensaje').first().json;
const filename = parsed.filename;
const mimeType = parsed.mime_type || 'application/octet-stream';
const from = parsed.from;
const fromName = parsed.from_name;
const phoneNumberId = parsed.phone_number_id;

let normalized = from.replace(/[\s\-\(\)\+]/g, '');
if (normalized.startsWith('0034')) normalized = normalized.slice(4);
if (normalized.length === 9) normalized = '34' + normalized;

const orgs = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/organizations`,
  qs: {
    'settings->whatsapp->>phone_number': `eq.${normalized}`,
    'select': 'id,nombre'
  },
  headers: {
    'apikey': SUPABASE_KEY,
    'Authorization': `Bearer ${SUPABASE_KEY}`,
  },
  json: true,
});

if (!orgs || orgs.length === 0) {
  return [{ json: { matched: false, senderPhone: normalized, phone_number_id: phoneNumberId } }];
}

const ORG_ID = orgs[0].id;
const ORG_NOMBRE = orgs[0].nombre;

// Get real base64 from binary (filesystem-v2 mode)
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');

const storagePath = `${ORG_ID}/${Date.now()}-${filename}`;

return [{
  json: {
    matched: true,
    org_id: ORG_ID,
    org_nombre: ORG_NOMBRE,
    filename: filename,
    storage_path: storagePath,
    mime_type: mimeType,
    from: from,
    from_name: fromName,
    base64: base64,
    phone_number_id: phoneNumberId,
    supabase_url: SUPABASE_URL,
    supabase_key: SUPABASE_KEY,
    documento_url: `${SUPABASE_URL}/storage/v1/object/public/facturas/${storagePath}`
  },
  binary: $input.first().binary
}];

