// ── // PR_BOT_2_5 helper: validateSpanishTaxId ──
function validateSpanishTaxId(raw) {
  if (!raw || typeof raw !== 'string') return { valid: false, kind: 'invalid' };
  const s = raw.toUpperCase().replace(/[\s\-\.]/g, '').trim();
  // DNI: 8 dígitos + letra
  if (/^\d{8}[A-Z]$/.test(s)) {
    const num = parseInt(s.slice(0, 8), 10);
    const expected = 'TRWAGMYFPDXBNJZSQVHLCKE'[num % 23];
    return { valid: s.slice(8) === expected, kind: 'dni' };
  }
  // NIE: [XYZ] + 7 dígitos + letra
  if (/^[XYZ]\d{7}[A-Z]$/.test(s)) {
    const subMap = { X: '0', Y: '1', Z: '2' };
    const numStr = subMap[s[0]] + s.slice(1, 8);
    const num = parseInt(numStr, 10);
    const expected = 'TRWAGMYFPDXBNJZSQVHLCKE'[num % 23];
    return { valid: s.slice(8) === expected, kind: 'nie' };
  }
  // CIF: letra org + 7 dígitos + (dígito | letra)
  if (/^[ABCDEFGHJNPQRSUVW]\d{7}[0-9A-J]$/.test(s)) {
    const inicial = s[0];
    const digits = s.slice(1, 8);
    const dc = s[8];
    let sumPares = 0, sumImpares = 0;
    for (let i = 0; i < 7; i++) {
      const d = parseInt(digits[i], 10);
      if (i % 2 === 0) {
        // posición impar (1,3,5,7 1-indexed) → doblar
        const doubled = d * 2;
        sumImpares += Math.floor(doubled / 10) + (doubled % 10);
      } else {
        sumPares += d;
      }
    }
    const total = sumPares + sumImpares;
    const dcDigit = (10 - (total % 10)) % 10;
    const dcLetter = 'JABCDEFGHI'[dcDigit];
    const letrasObligaLetra = 'PQRSNW';
    const letrasObligaDigito = 'ABEH';
    let ok;
    if (letrasObligaLetra.indexOf(inicial) >= 0) {
      ok = dc === dcLetter;
    } else if (letrasObligaDigito.indexOf(inicial) >= 0) {
      ok = dc === String(dcDigit);
    } else {
      // CDFGJUV → cualquiera
      ok = dc === String(dcDigit) || dc === dcLetter;
    }
    return { valid: ok, kind: 'cif' };
  }
  return { valid: false, kind: 'invalid' };
}

const raw = $json.output || $json.text || '';
let data;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  data = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  return [{ json: {
    error: true,
    message: 'El agente no devolvio un JSON valido. Intentalo de nuevo.',
    raw_from: $('Preparar Input Agente').first().json.raw_from,
    phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
  } }];
}

// ── // PR_BOT_2: cambio_org_solicitado (multi-org switcher) ──
// Si el agente devolvió tipo='cambio_org_solicitado', enviamos lista
// WhatsApp interactiva con CANDIDATE_ORGS. El downstream router decide.
if (data.tipo === 'cambio_org_solicitado') {
  const agentIn = $('Preparar Input Agente').first().json;
  let candidates = [];
  try {
    if (typeof agentIn.candidate_orgs === 'string' && agentIn.candidate_orgs) {
      candidates = JSON.parse(agentIn.candidate_orgs);
    } else if (Array.isArray(agentIn.candidate_orgs)) {
      candidates = agentIn.candidate_orgs;
    }
  } catch (_e) { candidates = []; }
  if (!Array.isArray(candidates) || candidates.length < 2) {
    // No hay multi-org real → degradar a mensaje texto.
    return [{ json: {
      error: true,
      conversacional: true,
      message: data.mensaje || 'Solo tienes una empresa activa. ¿Quieres cambiar la activa desde la web?',
      raw_from: agentIn.raw_from,
      phone_number_id: agentIn.phone_number_id,
    } }];
  }
  // // PR_BOT_2_2: si agente resolvió target_org_id inequívoco, bypass lista.
  // Validar que el UUID figura en candidates (defensa anti-LLM-inventando).
  let autoTargetId = null;
  let autoTargetNombre = null;
  if (data.target_org_id && typeof data.target_org_id === 'string') {
    const match = candidates.find(c => c && c.id === data.target_org_id);
    if (match) {
      autoTargetId = match.id;
      autoTargetNombre = match.nombre;
    }
  }
  if (autoTargetId) {
    return [{ json: {
      error: false,
      auto_cambio_org: true,
      target_org_id: autoTargetId,
      target_org_nombre: autoTargetNombre,
      message: data.mensaje || ('Cambio a ' + autoTargetNombre + '. Dime.'),
      raw_from: agentIn.raw_from,
      phone_number_id: agentIn.phone_number_id,
      normalized_phone: agentIn.normalized_phone || agentIn.sessionId,
      data: { tipo: 'cambio_org_directo' },
      resumen: '',
      totales: { base: 0, iva: 0, total: 0 },
      nuevos_productos: [],
    } }];
  }
  return [{ json: {
    error: false,
    enviar_lista_multi_org: true,
    message: data.mensaje || 'Vale, ¿a cuál cambio?',
    candidate_orgs: candidates.slice(0, 10),
    raw_from: agentIn.raw_from,
    phone_number_id: agentIn.phone_number_id,
    // Shape mínimo para evitar que downstream nodes que esperan estos
    // campos petenten — no se usan en el branch lista pero los rellenamos.
    data: { tipo: 'cambio_org_solicitado' },
    resumen: '',
    totales: { base: 0, iva: 0, total: 0 },
    nuevos_productos: [],
  } }];
}

// ── // PR_BOT_1: small_talk / conversación ──
// Si el agente devolvió tipo='conversacion', responder texto plano sin ⚠️
// ni resumen tipo 🧾. Reusa el reply-agent-error (texto simple) con prefix vacío.
if (data.tipo === 'conversacion') {
  return [{ json: {
    error: true,
    conversacional: true,
    message: data.mensaje || data.message || 'Dime.',
    raw_from: $('Preparar Input Agente').first().json.raw_from,
    phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
  } }];
}

// ── BRANCH NUEVO: convertir_presupuesto ──
// Si el agente devolvió tipo='convertir_presupuesto', el JSON NO trae lineas
// (correcto — la conversión copia las del presupuesto origen, no las inventa).
// Hacemos lookup directo a Supabase para obtener totales reales y construir
// un resumen específico para el botón de confirmación.
if (data.tipo === 'convertir_presupuesto') {
  // v2 — ambiguous_handler: si el agente devuelve un error controlado con
  // mensaje propio (desambiguación, no encontrado, etc.), propagamos su
  // mensaje al user en vez de sobrescribir con el genérico.
  if (data.error && data.mensaje) {
    // v3 — persist_listado_on_ambiguo: si trae candidates (lista de
    // presupuestos del CASO 2), persistimos chat_state para que el
    // siguiente turno ("qué tiene el 2") pueda resolver el UUID.
    // v4 — persist_listado_clean: incluir draft:null y current_doc:null para
    // que el merge shallow del endpoint borre cualquier draft viejo de la sesión
    // previa (si el user salta de un flujo a otro listado nuevo).
    if (Array.isArray(data.candidates) && data.candidates.length > 0) {
      try {
        const APP_URL = $env.APP_URL;
        const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
        const agentInput = $('Preparar Input Agente').first().json;
        // phone_e164_normalize_v1: añadir '+' si falta — endpoint exige E.164.
const _phRaw = (agentInput.normalized_phone || agentInput.sessionId || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
        const phoneReceptorId = agentInput.phone_number_id || '';
        const orgId = agentInput.org_id || '';
        if (APP_URL && SERVICE_KEY && phoneUser && phoneReceptorId && orgId) {
          await this.helpers.httpRequest({
            method: 'POST',
            url: `${APP_URL}/api/internal/voice/chat-state`,
            headers: {
              'x-service-key': SERVICE_KEY,
              'Content-Type': 'application/json',
            },
            body: {
              phone_user: phoneUser,
              phone_receptor_id: phoneReceptorId,
              org_id: orgId,
              current_view: 'mostrando_listado',
              state_json: {
                last_listado: {
                  kind: 'presupuestos',
                  items: data.candidates,
                  ts: new Date().toISOString(),
                },
                last_intent: data.tipo || 'convertir_presupuesto',
                draft: null,
                current_doc: null,
                resolved_slot: null,
              },
            },
            json: true,
            timeout: 3000,
          });
        }
      } catch (_e) {
        // fail-open: el listado ya se envía al user; perder persist es degradación, no error.
      }
    }
    return [{ json: {
      error: true,
      message: data.mensaje,
      raw_from: $('Preparar Input Agente').first().json.raw_from,
      phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
    }}];
  }
  if (!data.presupuesto_id) {
    return [{ json: {
      error: true,
      message: 'No tengo el ID del presupuesto. Reformula tu mensaje indicando el numero (ej: P2026-0042).',
      raw_from: $('Preparar Input Agente').first().json.raw_from,
      phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
    }}];
  }

  const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
  const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
  const orgId = $('Preparar Input Agente').first().json.org_id;

  const presResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/presupuestos?id=eq.${data.presupuesto_id}&org_id=eq.${orgId}&select=id,num,fecha,base,total,estado,cliente_id,lineas,clientes(nombre,nif)`,
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
    json: true
  });

  if (!presResp || presResp.length === 0) {
    return [{ json: {
      error: true,
      message: 'No encuentro ese presupuesto en tu organizacion. Verifica el numero.',
      raw_from: $('Preparar Input Agente').first().json.raw_from,
      phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
    }}];
  }

  const pres = presResp[0];
  const baseTotal = parseFloat(pres.base) || 0;
  const total = parseFloat(pres.total) || 0;
  const ivaTotal = total - baseTotal;
  const fmtConv = n => n.toFixed(2).replace('.', ',');

  // // PR_BOT_1_2: cabecera con org si multi-org
  const _agentIn = $('Preparar Input Agente').first().json;
  // PR_BOT_3_1: siempre mostrar org en cabecera si está disponible.
  const _multiSuffix = _agentIn.org_nombre ? ` · ${_agentIn.org_nombre}` : '';
  let resumen = `🔄 *CONVERTIR PRESUPUESTO → FACTURA${_multiSuffix}*\n`;
  resumen += `Origen: ${pres.num}\n`;
  resumen += `Cliente: ${pres.clientes?.nombre || 'Sin nombre'}\n`;
  if (pres.fecha) resumen += `Fecha presupuesto: ${pres.fecha}\n`;
  resumen += `\n`;

  const lineasPres = Array.isArray(pres.lineas) ? pres.lineas : [];
  lineasPres.forEach(l => {
    const cant = l.cantidad || 1;
    const precio = l.precio_unitario || 0;
    const concepto = l.concepto || l.descripcion || 'Servicio';
    resumen += `• ${cant}x ${concepto}: ${fmtConv(precio)} EUR/u = ${fmtConv(cant * precio)} EUR`;
    const tags = [];
    if ((l.descuento_pct || 0) > 0) tags.push(`-${l.descuento_pct}%`);
    if (l.iva_pct !== undefined && l.iva_pct !== 21) tags.push(`IVA ${l.iva_pct}%`);
    if (tags.length) resumen += ` (${tags.join(', ')})`;
    resumen += `\n`;
  });
  if (lineasPres.length === 0) {
    resumen += `_(Las lineas se copiaran del presupuesto al confirmar)_\n`;
  }

  resumen += `\nBase: ${fmtConv(baseTotal)} EUR\n`;
  resumen += `IVA: ${fmtConv(ivaTotal)} EUR\n`;
  resumen += `*TOTAL: ${fmtConv(total)} EUR*`;

  if (pres.estado === 'facturado') {
    resumen += `\n\n⚠️ _Este presupuesto ya esta facturado. Si confirmas, te devolvere la factura existente sin duplicar._`;
  }

  return [{ json: {
    error: false,
    data: { ...data, presupuesto_num: pres.num, total_estimado: total, cliente: { nombre: pres.clientes?.nombre || data.cliente?.nombre || 'Sin nombre' } },
    resumen,
    totales: { base: baseTotal, iva: ivaTotal, total },
    nuevos_productos: [],
    raw_from: $('Preparar Input Agente').first().json.raw_from,
    phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
  }}];
}

if (data.error) {
  return [{ json: {
    error: true,
    message: data.mensaje || 'No tengo suficiente informacion. Especifica el numero de factura o el cliente.',
    raw_from: $('Preparar Input Agente').first().json.raw_from,
    phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
  } }];
}

// ── // PR_BOT_2_4: defensa precio 0 / NIF faltante ──
// El LLM puede ignorar reglas del prompt. Cortamos en el código:
// no emitimos resumen 🧾 con precio falsy ni con factura sin NIF.
{
  const _tipo = (data.tipo || 'factura').toLowerCase();
  const _lineasCheck = Array.isArray(data.lineas) ? data.lineas : [];
  const _agentInGuard = $('Preparar Input Agente').first().json;
  if (_tipo === 'factura' || _tipo === 'abono' || _tipo === 'presupuesto' || _tipo === 'proforma') {
    // Línea con precio falsy y no marcada desde_catalogo → pedir precio.
    const _linMala = _lineasCheck.find(l => {
      const p = Number(l && l.precio_unitario);
      const fromCat = l && l.desde_catalogo === true;
      return !fromCat && (!Number.isFinite(p) || p <= 0);
    });
    if (_linMala) {
      const desc = (_linMala.descripcion || 'esta línea').toString().slice(0, 80);
      return [{ json: {
        error: true,
        conversacional: true,
        message: `Falta el precio de ${desc}. ¿A cuánto va por unidad?`,
        raw_from: _agentInGuard.raw_from,
        phone_number_id: _agentInGuard.phone_number_id,
      } }];
    }
  }
  // NIF obligatorio para factura. Abono hereda del cliente original.
  // convertir_presupuesto ya tiene su branch dedicado arriba.
  if (_tipo === 'factura') {
    const cli = (data.cliente || {});
    const nif = (cli.nif || '').toString().trim();
    const hasExistingId = cli.id && cli.crear !== true;
    // Si dice 'usar cliente id X' confiamos que ese cliente ya tiene NIF en BD
    // (el backend validará en createDocument). Solo bloqueamos si claramente falta.
    if (!nif && !hasExistingId) {
      const nombreCli = (cli.nombre || 'el cliente').toString().slice(0, 80);
      return [{ json: {
        error: true,
        conversacional: true,
        message: `Para emitir la factura necesito el NIF de ${nombreCli}. ¿Cuál es?`,
        raw_from: _agentInGuard.raw_from,
        phone_number_id: _agentInGuard.phone_number_id,
      } }];
    }
    // // PR_BOT_2_5: si trae NIF, validar algoritmo DNI/NIE/CIF.
    if (nif && !hasExistingId) {
      const v = validateSpanishTaxId(nif);
      if (!v.valid) {
        const nombreCli = (cli.nombre || 'el cliente').toString().slice(0, 80);
        return [{ json: {
          error: true,
          conversacional: true,
          message: `El NIF "${nif}" no es válido. Acepto DNI (8 dígitos+letra), NIE (X/Y/Z+7 dígitos+letra) o CIF (letra empresa+7 dígitos+dígito/letra). ¿Puedes confirmar el NIF de ${nombreCli}?`,
          raw_from: _agentInGuard.raw_from,
          phone_number_id: _agentInGuard.phone_number_id,
        } }];
      }
    }
  }
}

const lineas = (data.lineas || []).map(l => {
  const base = (l.cantidad || 0) * (l.precio_unitario || 0);
  const descLinea = base * ((l.descuento_pct || 0) / 100);
  const baseNeta = base - descLinea;
  const iva = baseNeta * ((l.iva_pct || 21) / 100);
  return { ...l, base: baseNeta, iva, _isNuevo: l.desde_catalogo === false };
});

const subtotal = lineas.reduce((s, l) => s + l.base, 0);
const descGlobalPct = data.descuento_global_pct || 0;
const descGlobal = subtotal * (descGlobalPct / 100);
const baseTotal = subtotal - descGlobal;
const ivaTotal = lineas.reduce((s, l) => s + l.iva, 0) * (1 - descGlobalPct / 100);
const total = baseTotal + ivaTotal;

const fmt = n => n.toFixed(2).replace('.', ',');

const tipoEmoji = data.tipo === 'presupuesto' ? '📋'
  : data.tipo === 'proforma' ? '📄'
  : data.tipo === 'abono' ? '↩️'
  : '🧾';

// // PR_BOT_1_2: cabecera con org si multi-org
const _agentIn2 = $('Preparar Input Agente').first().json;
// PR_BOT_3_1: siempre mostrar org en cabecera si está disponible.
const _multiSuffix2 = _agentIn2.org_nombre ? ` · ${_agentIn2.org_nombre}` : '';
let resumen = `${tipoEmoji} *${(data.tipo || 'factura').toUpperCase()}${_multiSuffix2}*\n`;
resumen += `Cliente: ${data.cliente?.nombre || 'Sin nombre'}\n\n`;

lineas.forEach(l => {
  const star = l._isNuevo ? '✨ ' : '';
  resumen += `• ${l.cantidad}x ${star}${l.descripcion}: ${fmt(l.precio_unitario)} EUR/u = ${fmt(l.cantidad * l.precio_unitario)} EUR`;
  const tags = [];
  if ((l.descuento_pct || 0) > 0) tags.push(`-${l.descuento_pct}%`);
  if (l.iva_pct !== undefined && l.iva_pct !== 21) tags.push(`IVA ${l.iva_pct}%`);
  if (tags.length) resumen += ` (${tags.join(', ')})`;
  resumen += '\n';
});

resumen += '\n';
if (descGlobalPct > 0) resumen += `Dto global: ${descGlobalPct}%\n`;
resumen += `Base: ${fmt(baseTotal)} EUR\n`;
resumen += `IVA: ${fmt(ivaTotal)} EUR\n`;
resumen += `*TOTAL: ${fmt(total)} EUR*`;

const nuevos = lineas.filter(l => l._isNuevo).map(l => l.descripcion);
if (nuevos.length > 0) {
  resumen += `\n\n✨ _Productos nuevos (no estan en tu catalogo): ${nuevos.join(', ')}_`;
}

return [{ json: {
  error: false,
  data,
  resumen,
  totales: { base: baseTotal, iva: ivaTotal, total },
  nuevos_productos: lineas.filter(l => l._isNuevo).map(l => ({
    nombre: l.descripcion,
    precio_orientativo: l.precio_unitario,
    iva_pct: l.iva_pct || 21
  })),
  raw_from: $('Preparar Input Agente').first().json.raw_from,
  phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
}}];

