// delivery_status_patch_v1
// Extrae el primer 'statuses[0]' del payload de Meta Cloud API y lo normaliza.
// Si el payload no trae 'statuses', devolvemos un objeto con skip=true y el
// IF previo ya nos habrá enviado por la rama 'false', así que esto solo
// corre cuando hay statuses.
const body = $input.first().json.body || $input.first().json;
const entry = (body && body.entry && body.entry[0]) || {};
const change = (entry.changes && entry.changes[0]) || {};
const value = change.value || {};
const status = (value.statuses && value.statuses[0]) || null;

if (!status) {
  return [{ json: { skip: true, reason: 'no_status_in_payload' } }];
}

const errors = Array.isArray(status.errors) ? status.errors : [];
const firstErr = errors[0] || {};

return [{
  json: {
    provider_message_id: status.id || null,
    status: status.status || null,                  // sent | delivered | read | failed
    recipient: status.recipient_id || null,         // E.164 sin '+'
    timestamp: status.timestamp || null,            // unix seconds (string)
    error_code: firstErr.code ?? null,
    error_subcode: firstErr.error_data?.details_subcode ?? null,
    error_title: firstErr.title || null,
    error_message: firstErr.message || null,
    conversation_id: status.conversation?.id || null,
    pricing_category: status.pricing?.category || null,
  }
}];

// phone_state_guard_v2 — Phone State Check
//
// Llama internamente al endpoint resolve-context preservando el item de
// Parsear Mensaje intacto. Spread propaga todos los campos (futuros incluidos).
//
// Convenciones del proyecto:
//   - Env APP_URL (en container n8n) — base del backend FacturaIA.
//     Coherente con apply-delivery-status.py y la doc del hub.
//   - Env FACTURAIA_SERVICE_KEY (en container n8n) — service-key del backend.
//
// Fail-open por diseño: si la API cae o la config está rota, el IF posterior
// cae a FALSE (match=null no matchea ningún 'equals') y el flujo sigue normal.
// Mejor procesar de más que cortar el bot a usuarios verified.
//
// Auditabilidad: en error se devuelve `phone_change_check_error` truncado a
// 120 chars (solo `err.message`, NUNCA headers, key, ni URL interpolada). Esto
// permite diagnosticar misconfigs/outage en n8n executions sin exponer secrets.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;

if (!APP_URL || !SERVICE_KEY) {
  // misconfig → fail-open con marca explícita (NO throw: el bot debe seguir
  // procesando para usuarios verified; el operator ve el error en executions).
  return [{
    json: {
      ...parsed,
      phone_change_match: null,
      phone_change_meta: null,
      phone_change_check_error: 'misconfig: missing APP_URL or FACTURAIA_SERVICE_KEY',
    },
  }];
}

const phone = parsed.normalized_phone;

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/internal/whatsapp/resolve-context`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: { from_phone: phone },
    json: true,
    timeout: 3000,
  });
  return [{
    json: {
      ...parsed,
      phone_change_match: resp?.phone_change_match ?? null,
      phone_change_meta: resp?.phone_change_meta ?? null,
    },
  }];
} catch (err) {
  // fail-open: capturamos solo err.message truncado para audit. NO incluimos
  // err completo (puede contener response body con headers/url), NO la key.
  const errMsg = String((err && err.message) ? err.message : err).slice(0, 120);
  return [{
    json: {
      ...parsed,
      phone_change_match: null,
      phone_change_meta: null,
      phone_change_check_error: errMsg,
    },
  }];
}

