const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;
const org = $('Buscar Org Texto').first().json;

// phone_e164_normalize_v1: añadir '+' si falta — endpoint exige E.164.
const _phRaw = (parsed.normalized_phone || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = parsed.phone_number_id || '';
const orgId = org?.org_id || parsed.org_id || '';

if (!APP_URL || !SERVICE_KEY || !phoneUser || !orgId) {
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      memberships_count: org?.memberships_count || 1,
      candidate_orgs: org?.candidate_orgs || null,
      previous_state: null,
      previous_state_json: null,
      is_first_time: true,  // PR_BOT_1
    },
  }];
}

try {
  // urlsearchparams_fix_v1: sandbox Code de n8n no expone URLSearchParams.
  const qs =
    'phone_user=' + encodeURIComponent(phoneUser) +
    '&phone_receptor_id=' + encodeURIComponent(phoneReceptorId) +
    '&org_id=' + encodeURIComponent(orgId);
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${APP_URL}/api/internal/voice/chat-state?${qs}`,
    headers: {
      'x-service-key': SERVICE_KEY,
    },
    json: true,
    timeout: 3000,
  });
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      memberships_count: org?.memberships_count || 1,
      candidate_orgs: org?.candidate_orgs || null,
      previous_state: resp?.current_view ?? null,
      previous_state_json: resp?.state_json ?? null,
      is_first_time: (resp?.current_view == null && resp?.state_json == null),  // PR_BOT_1
    },
  }];
} catch (err) {
  const errMsg = String((err && err.message) ? err.message : err).slice(0, 120);
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      memberships_count: org?.memberships_count || 1,
      candidate_orgs: org?.candidate_orgs || null,
      previous_state: null,
      previous_state_json: null,
      chat_state_resolve_error: errMsg,
      is_first_time: true,  // PR_BOT_1
    },
  }];
}

// v5-tool-fallback-draft — bot_state_machine_v1 + slot-resolver
//
// Devuelve el detalle de un presupuesto resuelto deterministicamente.
//
// Orden de resolución del UUID:
//   1. previous_state.resolved_slot.id (del slot resolver)
//   2. previous_state.draft.data.presupuesto_id (user pregunta sobre el
//      documento en curso, ej "qué tiene esto" durante awaiting_confirmation)
//   3. Si ninguno → devolver 'no_slot_resolved' para que el LLM pida número.
//
// NO usa $fromAI() — el LLM nunca pasa UUIDs (eliminamos bug
// 'Cannot assign to read only property name' de toolCode langchain).

const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const pia = $('Preparar Input Agente').first().json;
const orgId = pia.org_id;

let stateJson = pia.previous_state_json;
if (typeof stateJson === 'string' && stateJson) {
  try { stateJson = JSON.parse(stateJson); } catch (_e) { stateJson = null; }
}

// Resolver UUID con fallback ordenado.
let presupuestoId = null;
let source = null;
if (stateJson && stateJson.resolved_slot && stateJson.resolved_slot.id) {
  presupuestoId = stateJson.resolved_slot.id;
  source = 'resolved_slot';
} else if (
  stateJson &&
  stateJson.draft &&
  stateJson.draft.data &&
  stateJson.draft.data.presupuesto_id
) {
  presupuestoId = stateJson.draft.data.presupuesto_id;
  source = 'draft';
}

if (!presupuestoId) {
  return JSON.stringify({
    error: 'no_slot_resolved',
    mensaje: 'No hay un presupuesto resuelto. Pide al usuario que indique a cuál se refiere (ej: "el 1", "el primero", "P2026-0042", "el de 500 euros") sobre el último listado, o que pida primero el listado de presupuestos.',
  });
}

if (!APP_URL || !SERVICE_KEY || !orgId) {
  return JSON.stringify({
    error: 'misconfig',
    mensaje: 'Configuración incompleta (APP_URL/SERVICE_KEY/org_id). Pide al usuario que reintente en 1 minuto.',
  });
}

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/internal/voice/presupuesto-detalle`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: { presupuesto_id: presupuestoId, org_id: orgId },
    json: true,
    timeout: 5000,
  });
  return JSON.stringify({ ...resp, _source: source });
} catch (err) {
  const msg = String((err && err.message) ? err.message : err).slice(0, 200);
  return JSON.stringify({
    error: 'http_error',
    mensaje: 'Problema técnico consultando el detalle. Pide al usuario que reintente en 1 minuto.',
    debug: msg,
  });
}

// bot_state_machine_v1 — Persistir Chat State Doc
//
// Tras enviar PDF al usuario, persiste estado `post_action` con info del
// documento entregado. Fail-open: si falla, sólo log error, no rompe flujo.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const agentInput = $('Preparar Input Agente').first().json;
// phone_e164_normalize_v1: añadir '+' si falta — endpoint exige E.164.
const _phRaw = (agentInput.normalized_phone || agentInput.sessionId || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = agentInput.phone_number_id || '';
const orgId = agentInput.org_id || '';

// Best-effort: tomar info del doc del nodo de generación si existe.
let docInfo = null;
try {
  const gen = $('Generar Factura').first().json;
  docInfo = {
    tipo: gen?.tipo || null,
    id: gen?.id || gen?.factura_id || null,
    num: gen?.num || null,
  };
} catch (_e) {
  docInfo = null;
}

if (!APP_URL || !SERVICE_KEY || !phoneUser || !phoneReceptorId || !orgId) {
  return [{ json: { ...$json, persist_skipped: true } }];
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/internal/voice/chat-state`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: {
      phone_user: phoneUser,
      phone_receptor_id: phoneReceptorId,
      org_id: orgId,
      current_view: 'post_action',
      state_json: {
        current_doc: docInfo,
        last_intent: 'generar',
        ts: new Date().toISOString(),
      },
    },
    json: true,
    timeout: 3000,
  });
} catch (err) {
  // fail-open
}

return [{ json: $json }];

