parameters.jsCode:
// PR_BOT_3: criterio "hay sesión activa" — antes COUNT(*) n8n_chat_histories>0
// (cualquier history previa caía en path corrección). Ahora: chat_state.current_view
// = 'awaiting_confirmation' AND state_json.draft != null AND no expirado.
// Devuelve { cnt: 0|1 } para que Tiene Sesion? siga funcionando sin cambios downstream.
const BASE = $env.FACTURAIA_BASE_URL || $env.APP_URL || 'https://app.tufacturaia.com';
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;

const _phRaw = (parsed.normalized_phone || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = parsed.phone_number_id || '';

// Sin env/teléfono: fail-safe a cnt=0 (path normal). Mejor false-negative que falso path corrección.
if (!BASE || !SERVICE_KEY || !phoneUser || !phoneReceptorId) {
  return [{ json: { cnt: 0, pr_bot_3_skip_reason: 'missing_env_or_phone' } }];
}

let orgId = '';
try {
  const ctx = await this.helpers.httpRequest({
    method: 'POST',
    url: BASE + '/api/internal/whatsapp/resolve-context',
    headers: { 'x-service-key': SERVICE_KEY, 'Content-Type': 'application/json' },
    body: { from_phone: phoneUser },
    json: true,
    timeout: 3000,
  });
  if (ctx && ctx.matched && ctx.org_id) orgId = ctx.org_id;
} catch (err) {
  return [{ json: { cnt: 0, pr_bot_3_skip_reason: 'resolve_context_error', pr_bot_3_err: String((err && err.message) || err).slice(0, 120) } }];
}

if (!orgId) {
  return [{ json: { cnt: 0, pr_bot_3_skip_reason: 'no_org_matched' } }];
}

try {
  const qs =
    'phone_user=' + encodeURIComponent(phoneUser) +
    '&phone_receptor_id=' + encodeURIComponent(phoneReceptorId) +
    '&org_id=' + encodeURIComponent(orgId);
  const st = await this.helpers.httpRequest({
    method: 'GET',
    url: BASE + '/api/internal/voice/chat-state?' + qs,
    headers: { 'x-service-key': SERVICE_KEY },
    json: true,
    timeout: 3000,
  });
  const view = st && st.current_view ? st.current_view : null;
  const expired = st && st.expired === true;
  const draft = (st && st.state_json && typeof st.state_json === 'object') ? st.state_json.draft : null;
  const hasPendingDraft = !expired && view === 'awaiting_confirmation' && draft != null;
  return [{ json: {
    cnt: hasPendingDraft ? 1 : 0,
    pr_bot_3_view: view,
    pr_bot_3_expired: !!expired,
    pr_bot_3_org_id: orgId,
  } }];
} catch (err) {
  return [{ json: { cnt: 0, pr_bot_3_skip_reason: 'chat_state_error', pr_bot_3_err: String((err && err.message) || err).slice(0, 120) } }];
}

// // PR_BOT_1_3: llamar al endpoint canónico resolve-context
// (sender mode) en vez del lookup Supabase directo legacy. Esto da
// memberships_count real para que HAS_MULTI_ORG funcione en path corrección.
const BASE = $env.FACTURAIA_BASE_URL || 'https://app.tufacturaia.com';
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;
const normalized = parsed.normalized_phone;

let org = { id: '', nombre: '', memberships_count: 1 };
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${BASE}/api/internal/whatsapp/resolve-context`,
    headers: { 'x-service-key': SERVICE_KEY, 'Content-Type': 'application/json' },
    body: { from_phone: normalized },
    json: true,
    timeout: 3000,
  });
  if (resp?.matched) {
    org = {
      id: resp.org_id,
      nombre: resp.org_nombre || '',
      memberships_count: resp.memberships_count || 1,
      candidate_orgs: resp.candidate_orgs || null,  // PR_BOT_2
    };
  }
} catch (err) {
  // fail-open: degradamos a single-org silenciosamente.
  console.warn('[set-correction] resolve-context error', err?.message || err);
}

return [{ json: {
  correction_text: parsed.text_body,
  normalized_phone: normalized,
  raw_from: parsed.from,
  phone_number_id: parsed.phone_number_id,
  org_id: org.id,
  org_nombre: org.nombre,
  is_first_time: false,  // path corrección por definición no es first-time
  memberships_count: org.memberships_count,
  candidate_orgs: org.candidate_orgs || null,  // PR_BOT_2
}}];

// v2-process-button — gestiona button_reply de WhatsApp.
// WA_BOOST_V1_COBRO — además de los buttons clásicos (voice_confirm/cancel/correct),
// reconoce los prefixes `cobro_confirm:<factura_id>` y `cobro_reject:<factura_id>`
// generados por la rama de Fricción Inversa (B1, sprint próximo).

const buttonId = $('Parsear Mensaje').first().json.button_reply_id || '';

let intent = 'unknown';
let cobro_factura_id = null;

if (buttonId === 'voice_confirm') intent = 'confirm';
else if (buttonId === 'voice_cancel') intent = 'cancel';
else if (buttonId === 'voice_correct') intent = 'correct';
else if (buttonId.startsWith('cobro_confirm:')) {
  intent = 'cobro_confirm';
  cobro_factura_id = buttonId.slice('cobro_confirm:'.length) || null;
} else if (buttonId.startsWith('cobro_reject:')) {
  intent = 'cobro_reject';
  cobro_factura_id = buttonId.slice('cobro_reject:'.length) || null;
}

return [{ json: {
  session_id_hash: $('Hash Session').first().json.session_id_hash,
  intent,
  cobro_factura_id,
  normalized_phone: $('Parsear Mensaje').first().json.normalized_phone,
  raw_from: $('Parsear Mensaje').first().json.from,
  phone_number_id: $('Parsear Mensaje').first().json.phone_number_id
}}];

const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const rows = $input.all();
if (!rows.length) return [{ json: { error: true, message: 'No hay sesion de factura activa.' } }];

let raw = '';
for (const row of rows) {
  const msg = row.json && row.json.message;
  if (!msg) continue;
  const msgObj = typeof msg === 'string' ? JSON.parse(msg) : msg;
  if (msgObj.type === 'ai' || msgObj.type === 'AIMessage' || msgObj.type === 'assistant') {
    raw = (msgObj.data && msgObj.data.content) || msgObj.content || (typeof msg === 'string' ? msg : JSON.stringify(msg));
    break;
  }
}

if (!raw) {
  const firstMsg = rows[0] && rows[0].json && rows[0].json.message;
  const debug = typeof firstMsg === 'string' ? firstMsg.substring(0, 200) : JSON.stringify(firstMsg).substring(0, 200);
  return [{ json: { error: true, message: 'No se encontro respuesta del agente. Debug: ' + debug } }];
}

let data;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  data = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  return [{ json: { error: true, message: 'JSON invalido del agente. Raw: ' + raw.substring(0, 200) } }];
}

const phone = $('Procesar Boton').first().json.normalized_phone;

// Profile-only resolution (phone -> user -> org)
const profileResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/profiles?phone=eq.${phone}&select=user_id`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
  json: true
});
if (!profileResp || profileResp.length === 0) {
  return [{ json: { error: true, message: 'Tu telefono no esta registrado en ningun perfil de FacturaIA.' } }];
}
const user_id = profileResp[0].user_id;

const memberResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/org_members?user_id=eq.${user_id}&estado=eq.activo&select=org_id`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
  json: true
});
if (!memberResp || memberResp.length === 0) {
  return [{ json: { error: true, message: 'No perteneces a ninguna organizacion activa.' } }];
}
const org_id = memberResp[0].org_id;

// ── BRANCH NUEVO: convertir_presupuesto ──
// Si el agente devolvió tipo='convertir_presupuesto', cortocircuitamos el flujo
// normal (no hay líneas que normalizar, no hay que llamar /api/voice/generate).
// El siguiente IF "Es Conversion?" detecta flow='convert_presupuesto' y enruta
// al nodo HTTP que llama /api/voice/convert-presupuesto.
if (data.tipo === 'convertir_presupuesto') {
  if (data.error) {
    return [{ json: { error: true, message: data.mensaje || 'No pude convertir el presupuesto.' } }];
  }
  if (!data.presupuesto_id) {
    return [{ json: { error: true, message: 'Falta presupuesto_id en la respuesta del agente.' } }];
  }
  return [{ json: {
    error: false,
    flow: 'convert_presupuesto',
    org_id, user_id,
    presupuesto_id: data.presupuesto_id,
    presupuesto_num: data.presupuesto_num || null,
    total_estimado: data.total_estimado || null,
    phone,
    chat_id: phone,
    raw_from: $('Procesar Boton').first().json.raw_from,
    phone_number_id: $('Procesar Boton').first().json.phone_number_id
  }}];
}

const lineas = (data.lineas || []).map(l => ({
  concepto: l.descripcion || l.concepto,
  cantidad: l.cantidad,
  precio_unitario: l.precio_unitario,
  iva_pct: l.iva_pct || 21,
  descuento_pct: l.descuento_pct || 0
}));

return [{ json: {
  error: false,
  flow: 'generate',
  org_id,
  user_id,
  tipo: data.tipo || 'factura',
  factura_origen_id: data.factura_origen_id || null,
  cliente: data.cliente,
  lineas,
  descuento_global_pct: data.descuento_global_pct || 0,
  notas: data.notas || null,
  phone,
  raw_from: $('Procesar Boton').first().json.raw_from,
  phone_number_id: $('Procesar Boton').first().json.phone_number_id
}}];

