parameters.jsCode:
// Resuelve org del remitente via /api/internal/whatsapp/resolve-context
// (single source of truth). Maneja multi_org_pendiente.
const BASE = $env.FACTURAIA_BASE_URL || 'https://app.tufacturaia.com';
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;
const phone = parsed.normalized_phone;

let resolveResp;
try {
  resolveResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${BASE}/api/internal/whatsapp/resolve-context`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: { from_phone: phone, features_to_check: ['generador_voz'] },
    json: true,
  });
} catch (err) {
  console.error('[Buscar Org Texto] resolve-context error', err?.message || err);
  return [{ json: {
    matched: false, reason: 'resolve_context_unreachable',
    from: parsed.from, normalized_phone: phone,
    phone_number_id: parsed.phone_number_id,
    text_body: parsed.text_body,
    multi_org_pending: false,
    memberships_count: 1,  // PR_BOT_1_1
  }}];
}

const featOk = resolveResp.features?.generador_voz === true;
const isMultiPending = resolveResp.reason === 'multi_org_pendiente';

if (resolveResp.matched && featOk) {
  return [{ json: {
    matched: true,
    org_id: resolveResp.org_id,
    org_nombre: resolveResp.org_nombre,
    user_id: resolveResp.user_id,
    from: parsed.from,
    normalized_phone: phone,
    phone_number_id: parsed.phone_number_id,
    text_body: parsed.text_body,
    multi_org_pending: false,
    memberships_count: resolveResp.memberships_count || 1,  // PR_BOT_1_1
    candidate_orgs: resolveResp.candidate_orgs || null,  // PR_BOT_2
