// SPRINT_WA_BOOST_V1 — get_cashflow_forecast
// Devuelve previsión de tesorería. Sin args (org_id viene del input agente).
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const pia = $('Preparar Input Agente').first().json;
const orgId = pia.org_id;

if (!APP_URL || !SERVICE_KEY || !orgId) {
  return JSON.stringify({ error: 'misconfig', mensaje: 'Configuración incompleta.' });
}

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/voice/cashflow/get-forecast`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: { org_id: orgId, horizon_days: 30 },
    json: true,
    timeout: 6000,
  });
  return JSON.stringify(resp || {});
} catch (err) {
  const msg = String((err && err.message) ? err.message : err).slice(0, 200);
  return JSON.stringify({ error: 'http_error', mensaje: msg });
}

// SPRINT_WA_BOOST_V1 — registrar_gasto_rapido
// Args via $fromAI (LangChain): importe, concepto, proveedor?, fecha?
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const pia = $('Preparar Input Agente').first().json;
const orgId = pia.org_id;

const importe = $fromAI('importe', 'Importe del gasto en euros', 'number');
const concepto = $fromAI('concepto', 'Concepto / descripción breve', 'string');
const proveedor = $fromAI('proveedor', 'Nombre del proveedor (opcional)', 'string');
const fecha = $fromAI('fecha', 'Fecha del gasto YYYY-MM-DD (opcional)', 'string');

if (!importe || Number(importe) <= 0) {
  return JSON.stringify({ error: 'importe_invalid', mensaje: 'Importe inválido o ausente.' });
}
if (!concepto) {
  return JSON.stringify({ error: 'concepto_required', mensaje: 'Falta concepto.' });
}
if (!APP_URL || !SERVICE_KEY || !orgId) {
  return JSON.stringify({ error: 'misconfig', mensaje: 'Configuración incompleta.' });
}

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/voice/cashflow/registrar-gasto-rapido`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: { org_id: orgId, importe: Number(importe), concepto, proveedor: proveedor || null, fecha: fecha || null },
    json: true,
    timeout: 6000,
  });
  return JSON.stringify(resp || {});
} catch (err) {
  const msg = String((err && err.message) ? err.message : err).slice(0, 200);
  return JSON.stringify({ error: 'http_error', mensaje: msg });
}

// SPRINT_WA_BOOST_V1 — analizar_compra
// Args via $fromAI: importe (required), descripcion?
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const pia = $('Preparar Input Agente').first().json;
const orgId = pia.org_id;

const importe = $fromAI('importe', 'Importe de la compra a evaluar (€)', 'number');
const descripcion = $fromAI('descripcion', 'Breve descripción de la compra (opcional)', 'string');

if (!importe || Number(importe) <= 0) {
  return JSON.stringify({ error: 'importe_invalid', mensaje: 'Importe inválido o ausente.' });
}
if (!APP_URL || !SERVICE_KEY || !orgId) {
  return JSON.stringify({ error: 'misconfig', mensaje: 'Configuración incompleta.' });
}

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/voice/cashflow/analisis-compra`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: { org_id: orgId, importe: Number(importe), descripcion: descripcion || null },
    json: true,
    timeout: 6000,
  });
  return JSON.stringify(resp || {});
} catch (err) {
  const msg = String((err && err.message) ? err.message : err).slice(0, 200);
  return JSON.stringify({ error: 'http_error', mensaje: msg });
}

